#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005; 
int n,m,p,t,cnt,a[N],ans[N];
struct node
{
	int a,b,id,dis;
	bool operator<(const node other) const
	{
		if(b==other.b) return dis>other.dis;
		return b<other.b;
	}
} b[N];

int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>p>>t;
	for(int i=1;i<=m;i++)
	{
		int ss,tt,aa,bb,c,d;
		cin>>ss>>tt>>aa>>bb>>c>>d;
		b[++cnt]=node{ss,aa,i,0};
		b[++cnt]=node{tt,d,i,c-bb};
	}
	b[++cnt]=node{n+1,t,0,-0x3f3f3f3f};
	sort(b+1,b+1+cnt);
	memset(a,128,sizeof(a));
	a[1]=0;
	for(int i=1;i<=cnt;i++)
	{
		if(b[i].a==n+1) break;
		if(b[i].dis==0) ans[b[i].id]=a[b[i].a];
		else a[b[i].a]=max(a[b[i].a],ans[b[i].id]+b[i].dis);
	}
	if(a[p]<0) cout<<-1;
	else cout<<t-a[p];
	return 0;
}
